1	import { useCallback } from 'react';
2	import {
3	  KeyboardAvoidingView,
4	  Platform,
5	  Pressable,
6	  SafeAreaView,
7	  ScrollView,
8	  StyleSheet,
9	  Text,
10	  TextInput,
11	  View,
12	} from 'react-native';
13	import { router } from 'expo-router';
14	import { ChevronLeft, Trash2 } from 'lucide-react-native';
15	import { ButtonPrimary, ButtonSecondary } from '@/components/primitives/Button';
16	import { Chip } from '@/components/primitives/Chip';
17	import { colors, radii, shadows, spacing } from '@/design/tokens';
18	import { textStyles } from '@/design/typography';
19	import {
20	  useWizard,
21	  type WizardPreCondition,
22	  type WizardPreConditionMetric,
23	  type WizardPreConditionPlatform,
24	} from '@/screens/campaign-wizard/WizardStore';
25	
26	// US-050 — Create-campaign wizard step 2 (pre-conditions). Each row captures a
27	// single eligibility rule: platform + metric + numeric threshold. Operator is
28	// fixed at ">=" per the story AC and maps to `listing_conditions.operator = 'gte'`
29	// at step-5 publish time.
30	//
31	// Rows are stored in the wizard draft (AsyncStorage-backed, see WizardStore).
32	// UI metric keys ('followers' / 'avg_views') are intentionally UI-friendly and
33	// get mapped to DB `condition_metric` values ('min_followers' / 'min_avg_views_last_n')
34	// during publish — keeping the wizard store decoupled from the DB enum names
35	// means we can evolve either side without cross-stepping migrations.
36	//
37	// Pre-conditions are optional — an empty list is a valid "open to everyone"
38	// listing. Next is always enabled.
39	
40	const PLATFORMS: readonly { value: WizardPreConditionPlatform; label: string }[] = [
41	  { value: 'tiktok', label: 'TikTok' },
42	  { value: 'instagram', label: 'Instagram' },
43	];
44	
45	const METRICS: readonly { value: WizardPreConditionMetric; label: string }[] = [
46	  { value: 'followers', label: 'Followers' },
47	  { value: 'avg_views', label: 'Avg views' },
48	];
49	
50	// Digits only; empty string clears. `maxLength` on the input caps at 12 digits
51	// (≈ 1 trillion) which is well beyond any realistic follower/view threshold
52	// while keeping the cast safe from overflow into BigInt territory.
53	const THRESHOLD_INPUT_RE = /^\d*$/;
54	
55	function makeLocalId(): string {
56	  return `cnd_${Date.now().toString(36)}_${Math.random().toString(36).slice(2, 8)}`;
57	}
58	
59	export default function CampaignWizardStep2() {
60	  const { draft, updateField } = useWizard();
61	
62	  // All three mutations use `updateField`'s functional updater so rapid-fire
63	  // taps (e.g. "Add condition" pressed twice before a re-render) read the
64	  // latest array rather than the closure-captured snapshot.
65	  const onAddRow = useCallback(() => {
66	    const row: WizardPreCondition = {
67	      id: makeLocalId(),
68	      platform: 'tiktok',
69	      metric: 'followers',
70	      threshold: 0,
71	    };
72	    updateField('preConditions', (prev) => [...prev, row]);
73	  }, [updateField]);
74	
75	  const onRemoveRow = useCallback(
76	    (id: string) => {
77	      updateField('preConditions', (prev) => prev.filter((row) => row.id !== id));
78	    },
79	    [updateField],
80	  );
81	
82	  const onUpdateRow = useCallback(
83	    (id: string, patch: Partial<Omit<WizardPreCondition, 'id'>>) => {
84	      updateField('preConditions', (prev) =>
85	        prev.map((row) => (row.id === id ? { ...row, ...patch } : row)),
86	      );
87	    },
88	    [updateField],
89	  );
90	
91	  const onNext = useCallback(() => {
92	    router.push('/(lister)/campaigns/new/step-3');
93	  }, []);
94	
95	  const onBack = useCallback(() => {
96	    if (router.canGoBack()) router.back();
97	    else router.replace('/(lister)/campaigns/new/step-1');
98	  }, []);
99	
100	  return (
101	    <SafeAreaView style={styles.root}>
102	      <KeyboardAvoidingView
103	        style={styles.flex}
104	        behavior={Platform.OS === 'ios' ? 'padding' : undefined}
105	      >
106	        <ScrollView
107	          contentContainerStyle={styles.scroll}
108	          keyboardShouldPersistTaps="handled"
109	        >
110	          <View style={styles.header}>
111	            <Pressable
112	              onPress={onBack}
113	              hitSlop={{ top: 12, bottom: 12, left: 12, right: 12 }}
114	              accessibilityRole="button"
115	              accessibilityLabel="Back"
116	              testID="wizard-step2-back"
117	              style={styles.backBtn}
118	            >
119	              <ChevronLeft size={24} color={colors.ink} />
120	            </Pressable>
121	            <Text style={[textStyles.micro, styles.stepLabel]} allowFontScaling={false}>
122	              Step 2 of 5
123	            </Text>
124	            <Text style={[textStyles.display, styles.title]} maxFontSizeMultiplier={1.3}>
125	              Who can apply?
126	            </Text>
