41	  bytes[8] = (bytes[8] & 0x3f) | 0x80;
42	  const hex = bytes.map((b) => b.toString(16).padStart(2, '0')).join('');
43	  return `${hex.slice(0, 8)}-${hex.slice(8, 12)}-${hex.slice(12, 16)}-${hex.slice(16, 20)}-${hex.slice(20, 32)}`;
