1	// Edge function: apply-to-listing (US-041)
2	//
3	// Contract:
4	//   POST { listing_id: string, cover_note?: string }
5	//     → 200 { application_id: string, listing_version_id: string }
6	//     → 400 { error: 'INVALID_JSON' | 'INVALID_REQUEST' }
7	//     → 401 { error: 'UNAUTHORIZED' }
8	//     → 403 { error: 'FORBIDDEN' }                      // non-creator role
9	//     → 403 { error: 'INELIGIBLE',
10	//             failed_conditions: Array<{metric, platform, required, actual}> }
11	//     → 404 { error: 'LISTING_NOT_FOUND' }              // also covers draft/archived
12	//     → 409 { error: 'LISTING_NOT_ACTIVE' }
13	//     → 409 { error: 'LISTING_VERSION_CHANGED',
14	//             current_version_id: string }
15	//     → 409 { error: 'ALREADY_APPLIED' }
16	//     → 500 { error: 'SERVER_MISCONFIGURED' | 'DB_ERROR' }
17	//
18	// Auth: Marketify JWT (HS256, MARKETIFY_JWT_SECRET). Verifies via
19	//       _shared/jwt.ts and asserts role='creator'. Deployed with
20	//       verify_jwt=false at the gateway because the gateway only knows
21	//       about Supabase's own JWT secret — the handler enforces auth.
22	//
23	// Request shape — canonical per docs/tech-architecture.md §5.5
24	// (Req: `{ listing_id, cover_note? }`). The US-041 story AC names the
25	// optional field `pitch`; the spec name `cover_note` wins per the Ralph
26	// iteration rules and also matches the `public.applications.cover_note`
27	// column.
28	//
29	// Concurrency — we re-run eligibility in TS against the current version
30	// of the listing, then hand the same `expected_version_id` to the
31	// `public.apply_to_listing_rpc` RPC, which re-reads the listing under a
32	// row-level lock (SELECT ... FOR UPDATE). If the lister's version bump
33	// interleaves, the RPC sees a different current_version_id and returns
34	// LISTING_VERSION_CHANGED. This satisfies the §5.5 "re-run eligibility
35	// against the NOW-current version_id" invariant without duplicating the
36	// eligibility engine in PL/pgSQL. Spec §5.5 also enumerates
37	// LISTING_NOT_ACTIVE and ALREADY_APPLIED, both surfaced here.
38	//
39	// Fail-closed on missing metrics — inherited from the shared eligibility
40	// engine (docs/tech-architecture.md §3d): missing creator_profiles row,
41	// null platform fields, or unknown operators on a PRE condition all
42	// count as ineligible.
43	
44	import { createClient } from "npm:@supabase/supabase-js@2";
45	import { verifyJwt } from "../_shared/jwt.ts";
46	import { corsHeaders } from "../_shared/cors.ts";
47	import {
48	  type ConditionRow,
49	  type CreatorProfileRow,
50	  EMPTY_CREATOR_METRICS,
51	  evaluatePreConditions,
52	} from "../_shared/eligibility.ts";
53	
54	const UUID_RE =
55	  /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
56	
57	// Hard cap on cover_note — the schema column is `text` (unlimited), but
58	// anything longer than a few paragraphs is almost certainly abuse or
59	// accidental paste. 2000 chars = roughly 400 words, plenty for a pitch.
60	const COVER_NOTE_MAX_LEN = 2000;
61	
62	interface ApplyRequest {
63	  listing_id?: unknown;
64	  cover_note?: unknown;
65	}
66	
67	function jsonResponse(status: number, body: unknown): Response {
68	  return new Response(JSON.stringify(body), {
69	    status,
70	    headers: { ...corsHeaders, "Content-Type": "application/json" },
71	  });
72	}
73	
74	function bearerToken(req: Request): string | null {
75	  const raw = req.headers.get("Authorization") ??
76	    req.headers.get("authorization");
77	  if (!raw) return null;
78	  const m = raw.match(/^Bearer\s+(.+)$/i);
79	  return m ? m[1].trim() : null;
80	}
81	
82	Deno.serve(async (req) => {
83	  if (req.method === "OPTIONS") {
84	    return new Response(null, { status: 204, headers: corsHeaders });
85	  }
86	  if (req.method !== "POST") {
87	    return jsonResponse(405, { error: "METHOD_NOT_ALLOWED" });
88	  }
89	
90	  const token = bearerToken(req);
91	  if (!token) return jsonResponse(401, { error: "UNAUTHORIZED" });
92	
93	  let claims;
94	  try {
95	    claims = await verifyJwt(token);
96	  } catch {
97	    return jsonResponse(401, { error: "UNAUTHORIZED" });
98	  }
99	  if (claims.app_role !== "creator") {
100	    return jsonResponse(403, { error: "FORBIDDEN" });
101	  }
102	
103	  let body: ApplyRequest;
104	  try {
105	    body = await req.json();
106	  } catch {
107	    return jsonResponse(400, { error: "INVALID_JSON" });
108	  }
109	
110	  const listingId =
111	    typeof body.listing_id === "string" && UUID_RE.test(body.listing_id)
112	      ? body.listing_id
113	      : null;
114	  if (!listingId) {
115	    return jsonResponse(400, { error: "INVALID_REQUEST" });
116	  }
117	
118	  let coverNote: string | null = null;
119	  if (body.cover_note !== undefined && body.cover_note !== null) {
120	    if (typeof body.cover_note !== "string") {
121	      return jsonResponse(400, { error: "INVALID_REQUEST" });
122	    }
123	    const trimmed = body.cover_note.trim();
124	    if (trimmed.length > COVER_NOTE_MAX_LEN) {
125	      return jsonResponse(400, { error: "INVALID_REQUEST" });
126	    }
127	    coverNote = trimmed.length > 0 ? trimmed : null;
128	  }
129	
130	  const supabaseUrl = Deno.env.get("SUPABASE_URL");
131	  const serviceRoleKey = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY");
132	  if (!supabaseUrl || !serviceRoleKey) {
133	    return jsonResponse(500, { error: "SERVER_MISCONFIGURED" });
134	  }
135	
136	  const supabase = createClient(supabaseUrl, serviceRoleKey, {
137	    auth: { persistSession: false, autoRefreshToken: false },
138	  });
139	
140	  const { data: listing, error: listingError } = await supabase
141	    .from("listings")
142	    .select("id,status,current_version_id")
143	    .eq("id", listingId)
144	    .maybeSingle();
145	
146	  if (listingError) {
147	    console.error("listings lookup failed", listingError);
148	    return jsonResponse(500, { error: "DB_ERROR" });
149	  }
150	  // Draft and archived collapse to 404 to match get-listing-detail's
151	  // visibility rules — there's nothing to apply to and we don't want to
152	  // leak id existence.
153	  if (!listing || listing.status === "draft" || listing.status === "archived") {
154	    return jsonResponse(404, { error: "LISTING_NOT_FOUND" });
155	  }
156	  // Non-active (paused / closed) listings are a 409 per §5.5. They are
157	  // visible for detail view but not applyable.
158	  if (listing.status !== "active") {
159	    return jsonResponse(409, { error: "LISTING_NOT_ACTIVE" });
160	  }
161	
162	  const versionId = listing.current_version_id as string | null;
163	  if (!versionId) {
164	    console.error("listing missing current_version_id", listing.id);
165	    return jsonResponse(500, { error: "DB_ERROR" });
166	  }
167	
168	  const [conditionsRes, profileRes] = await Promise.all([
169	    supabase
170	      .from("listing_conditions")
171	      .select("*")
172	      .eq("listing_version_id", versionId),
173	    supabase
174	      .from("creator_profiles")
175	      .select(
176	        "tiktok_follower_count,tiktok_avg_views_last_10,tiktok_total_likes," +
177	          "tiktok_video_count,tiktok_is_verified,instagram_follower_count," +
178	          "instagram_avg_views_last_10,instagram_media_count",
179	      )
180	      .eq("user_id", claims.sub)
181	      .maybeSingle(),
182	  ]);
183	
184	  if (conditionsRes.error) {
185	    console.error("listing_conditions lookup failed", conditionsRes.error);
186	    return jsonResponse(500, { error: "DB_ERROR" });
187	  }
188	  if (profileRes.error) {
189	    console.error("creator_profiles lookup failed", profileRes.error);
190	    return jsonResponse(500, { error: "DB_ERROR" });
191	  }
192	
193	  const conditions = (conditionsRes.data ?? []) as ConditionRow[];
194	  const metrics: CreatorProfileRow = profileRes.data ?? EMPTY_CREATOR_METRICS;
195	  const failed = evaluatePreConditions(conditions, metrics);
196	  if (failed.length > 0) {
197	    return jsonResponse(403, {
198	      error: "INELIGIBLE",
199	      failed_conditions: failed,
200	    });
201	  }
202	
203	  const { data: rpcData, error: rpcError } = await supabase.rpc(
204	    "apply_to_listing_rpc",
205	    {
206	      p_listing_id: listingId,
207	      p_creator_id: claims.sub,
208	      p_expected_version_id: versionId,
209	      p_cover_note: coverNote,
210	    },
211	  );
212	
213	  if (rpcError) {
214	    console.error("apply_to_listing_rpc error", rpcError);
215	    return jsonResponse(500, { error: "DB_ERROR" });
216	  }
217	
218	  const result = rpcData as
219	    | {
220	      application_id?: string;
221	      listing_version_id?: string;
222	      error?: string;
223	      current_version_id?: string;
224	    }
225	    | null;
226	
227	  if (result?.error === "LISTING_NOT_FOUND") {
228	    return jsonResponse(404, { error: "LISTING_NOT_FOUND" });
229	  }
230	  if (result?.error === "LISTING_NOT_ACTIVE") {
231	    return jsonResponse(409, { error: "LISTING_NOT_ACTIVE" });
232	  }
233	  if (result?.error === "LISTING_VERSION_CHANGED") {
234	    return jsonResponse(409, {
235	      error: "LISTING_VERSION_CHANGED",
236	      current_version_id: result.current_version_id,
237	    });
238	  }
239	  if (result?.error === "ALREADY_APPLIED") {
240	    return jsonResponse(409, { error: "ALREADY_APPLIED" });
241	  }
242	
243	  if (!result?.application_id || !result.listing_version_id) {
244	    console.error("apply_to_listing_rpc returned unexpected shape", result);
245	    return jsonResponse(500, { error: "DB_ERROR" });
246	  }
247	
248	  return jsonResponse(200, {
249	    application_id: result.application_id,
250	    listing_version_id: result.listing_version_id,
251	  });
252	});
